ClientPlayer = class("ClientPlayer", BasePlayer)

PlayerManager:registerClientPlayerClass(ClientPlayer)
PlayerManager:registerOtherPlayerClass(ClientPlayer)

function ClientPlayer:init()
    GameInfoManager:registerObserver(self.userId, function(info)
        self:onPlayerInfoUpdate(info)
    end)
    self.lastShowHP = 0
    self.lastShowName = ""
end

function ClientPlayer:isMe()
    return tostring(self.userId) == tostring(Game:getPlatformUserId())
end

function ClientPlayer:onPlayerSpawn()
    local info = GameInfoManager:getPlayerInfo(self.userId)
    if not info then
        return
    end
    if StoreConfig and self:isMe() then
        StoreConfig:resetGoodsStore()
    end
    self:onPlayerInfoUpdate(info)
end

function ClientPlayer:onPlayerInfoUpdate(info)
    ---宠物相关
    local petId = tonumber(info:getValue("petId"))
    if tonumber(petId) == 0 then
        PetManager:subPet(self, tostring(petId))
        return
    end

    if self.Player then
        PetManager:addPet(self, tostring(petId))
    end
end

function ClientPlayer:onUpdate()
    if not self.Player then
        return
    end
    local showName = self.Player:getShowName()
    local curHp = math.floor(self.Player:getHealth() + 0.5)
    if self.lastShowHP == curHp and self.lastShowName == showName then
        return
    end
    self.lastShowHP = curHp
    local nameList = StringUtil.split(showName, "\n")
    if string.find(showName, "♥") then
        table.remove(nameList)
    end
    local hpText = "▢FFFFFFFF" .. tostring(curHp) .. "▢FFFF1F1F  ♥  "
    table.insert(nameList, hpText)
    self.lastShowName = table.concat(nameList, "\n")
    self.Player:setShowName(self.lastShowName)
end

function ClientPlayer:onLogout()
    if isGameStart then
        return
    end
    GameInfoManager:clearInfo("PlayerInfo", self.userId)
end